import { useUsers } from '#users/ui/context/users_context'
import { UsersActionDialog } from '#dashboard/ui/components/users/dialogs/users_action_dialog'
import { UsersDeleteDialog } from '#dashboard/ui/components/users/dialogs/users_delete_dialog'
import { UsersInviteDialog } from '#dashboard/ui/components/users/dialogs/users_invite_dialog'
import { UsersImpersonateDialog } from '#dashboard/ui/components/users/dialogs/users_impersonate_dialog'
import { UsersBanDialog } from '#dashboard/ui/components/users/dialogs/users_ban_dialog'
import { UsersUnBanDialog } from '#dashboard/ui/components/users/dialogs/users_unban_dialog'
import RoleDto from '#users/dtos/role'

export function UsersDialogs({ roles }: { roles: RoleDto[] }) {
  const { open, setOpen, currentRow, setCurrentRow } = useUsers()
  return (
    <>
      <UsersActionDialog
        key="user-add"
        roles={roles}
        open={open === 'add'}
        onOpenChange={() => setOpen('add')}
      />

      <UsersInviteDialog
        key="user-invite"
        roles={roles}
        open={open === 'invite'}
        onOpenChange={() => setOpen('invite')}
      />

      {currentRow && (
        <>
          <UsersBanDialog
            key={`user-ban-${currentRow.uuid}`}
            open={open === 'ban'}
            onOpenChange={() => {
              setOpen('ban')
              setTimeout(() => {
                setCurrentRow(null)
              }, 500)
            }}
            currentRow={currentRow}
          />
          <UsersUnBanDialog
            key={`user-unban-${currentRow.uuid}`}
            open={open === 'unban'}
            onOpenChange={() => {
              setOpen('unban')
              setTimeout(() => {
                setCurrentRow(null)
              }, 500)
            }}
            currentRow={currentRow}
          />
          <UsersImpersonateDialog
            key={`user-impersonate-${currentRow.uuid}`}
            open={open === 'impersonate'}
            onOpenChange={() => {
              setOpen('impersonate')
              setTimeout(() => {
                setCurrentRow(null)
              }, 500)
            }}
            currentRow={currentRow}
          />

          <UsersActionDialog
            key={`user-edit-${currentRow.uuid}`}
            roles={roles}
            open={open === 'edit'}
            onOpenChange={() => {
              setOpen('edit')
              setTimeout(() => {
                setCurrentRow(null)
              }, 500)
            }}
            currentRow={currentRow}
          />

          <UsersDeleteDialog
            key={`user-delete-${currentRow.uuid}`}
            open={open === 'delete'}
            onOpenChange={() => {
              setOpen('delete')
              setTimeout(() => {
                setCurrentRow(null)
              }, 500)
            }}
            currentRow={currentRow}
          />
        </>
      )}
    </>
  )
}

import {
  EditIcon,
  TrashIcon,
  EllipsisIcon,
  UserRoundSearch,
  Hammer,
  ShieldCheck,
} from 'lucide-react'

import { Button } from '@workspace/ui/components/button'
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuShortcut,
  DropdownMenuTrigger,
} from '@workspace/ui/components/dropdown-menu'
import { DataTableRowActionsProps } from '@workspace/ui/components/data-table/data-table'

import { useUsers } from '#users/ui/context/users_context'
import useUser from '#auth/ui/hooks/use_user'
import { useTranslation } from '#common/ui/hooks/use_translation'

import type UserDto from '#users/dtos/user'

export function DataTableRowActions({ row }: DataTableRowActionsProps<UserDto>) {
  const { setOpen, setCurrentRow } = useUsers()
  const user = useUser()
  const { t } = useTranslation()

  return (
    <DropdownMenu modal={false}>
      <DropdownMenuTrigger asChild>
        <Button variant="ghost" className="flex h-8 w-8 p-0 data-[state=open]:bg-muted">
          <EllipsisIcon className="h-4 w-4" />
          <span className="sr-only">{t('users.index.table.row_actions.open_menu')}</span>
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end" className="w-[160px]">
        {user.uuid !== row.original.uuid && (
          <DropdownMenuItem
            onClick={() => {
              setCurrentRow(row.original)
              setOpen('impersonate')
            }}
          >
            {t('users.index.table.row_actions.impersonate')}
            <DropdownMenuShortcut>
              <UserRoundSearch size={16} />
            </DropdownMenuShortcut>
          </DropdownMenuItem>
        )}
        <DropdownMenuItem
          onClick={() => {
            setCurrentRow(row.original)
            setOpen('edit')
          }}
        >
          {t('users.index.table.row_actions.edit')}
          <DropdownMenuShortcut>
            <EditIcon size={16} />
          </DropdownMenuShortcut>
        </DropdownMenuItem>
        <DropdownMenuSeparator />
        <DropdownMenuItem
          onClick={() => {
            setCurrentRow(row.original)
            setOpen('delete')
          }}
          className="text-destructive"
        >
          {t('users.index.table.row_actions.delete')}
          <DropdownMenuShortcut>
            <TrashIcon size={16} />
          </DropdownMenuShortcut>
        </DropdownMenuItem>
        {row.original.isBanned ? (
          <DropdownMenuItem
            onClick={() => {
              setCurrentRow(row.original)
              setOpen('unban')
            }}
            className="text-primary"
          >
            Débannir
            <DropdownMenuShortcut>
              <ShieldCheck size={16} />
            </DropdownMenuShortcut>
          </DropdownMenuItem>
        ) : (
          <DropdownMenuItem
            onClick={() => {
              setCurrentRow(row.original)
              setOpen('ban')
            }}
            className="text-destructive"
          >
            Bannir
            <DropdownMenuShortcut>
              <Hammer size={16} />
            </DropdownMenuShortcut>
          </DropdownMenuItem>
        )}
      </DropdownMenuContent>
    </DropdownMenu>
  )
}

import React from 'react'
import { useForm } from '@inertiajs/react'

import { Button } from '@workspace/ui/components/button'
import { PasswordInput } from '@workspace/ui/components/password-input'
import {
  Dialog,
  DialogClose,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@workspace/ui/components/dialog'
import { ScrollArea } from '@workspace/ui/components/scroll-area'
import { Input } from '@workspace/ui/components/input'
import { Field, FieldLabel } from '@workspace/ui/components/field'
import { Progress } from '@workspace/ui/components/progress'
import { toast } from '@workspace/ui/hooks/use-toast'
import {
  Select,
  SelectTrigger,
  SelectValue,
  SelectContent,
  SelectGroup,
  SelectItem,
} from '@workspace/ui/components/select'
import { FieldErrorBag } from '@workspace/ui/components/field-error-bag'
import { useTranslation } from '#common/ui/hooks/use_translation'

import type UserDto from '#users/dtos/user'
import RoleDto from '#users/dtos/role'

interface Props {
  roles: RoleDto[]
  currentRow?: UserDto
  open: boolean
  onOpenChange: (open: boolean) => void
}

export function UsersActionDialog({ roles, currentRow, open, onOpenChange }: Props) {
  const { t } = useTranslation()

  const isEdit = !!currentRow

  const { data, setData, errors, post, put, progress, clearErrors, reset } = useForm({
    fullName: currentRow && currentRow.fullName ? currentRow.fullName : '',
    email: currentRow ? currentRow.email : '',
    roleUuid: currentRow ? String(currentRow.roleUuid) : '',
    password: '',
    passwordConfirmation: '',
  })

  function handleSubmit(e: React.FormEvent) {
    e.preventDefault()

    const url = isEdit ? `/dashboard/users/${currentRow?.uuid}` : '/dashboard/users'
    const method = isEdit ? put : post

    method(url, {
      preserveScroll: true,
      preserveState: false,
      onSuccess: () => {
        onOpenChange(false)
        setTimeout(() => {
          reset()
          clearErrors()
        }, 500)
        toast(t('users.action.toast.title'), {
          description: (
            <div className="mt-2 max-w-[320px] overflow-x-auto rounded-md bg-slate-950 p-4">
              <pre className="text-white whitespace-pre-wrap break-words">
                <code>{JSON.stringify(data, null, 2)}</code>
              </pre>
            </div>
          ),
        })
      },
    })
  }

  return (
    <Dialog
      open={open}
      onOpenChange={(state) => {
        onOpenChange(state)
        setTimeout(() => {
          reset()
          clearErrors()
        }, 500)
      }}
    >
      <DialogContent className="sm:max-w-md">
        <DialogHeader className="text-left">
          <DialogTitle className="flex items-center gap-2">
            {t(isEdit ? 'users.action.edit.title' : 'users.action.create.title')}
          </DialogTitle>
          <DialogDescription>
            {t(isEdit ? 'users.action.edit.description' : 'users.action.create.description')}
          </DialogDescription>
        </DialogHeader>
        <ScrollArea>
          <form id="user-form" onSubmit={handleSubmit} className="space-y-4 p-0.5">
            <Field>
              <FieldLabel htmlFor="fullName">{t('users.action.form.full_name.label')}</FieldLabel>
              <Input
                id="fullName"
                placeholder={t('users.action.form.full_name.placeholder')}
                value={data.fullName}
                onChange={(element) => setData('fullName', element.target.value)}
                className={`${errors?.fullName ? 'border-destructive' : ''}`}
              />
              <FieldErrorBag errors={errors} field="fullName" />
            </Field>

            <Field>
              <FieldLabel htmlFor="email">{t('users.action.form.email.label')}</FieldLabel>
              <Input
                id="email"
                placeholder={t('users.action.form.email.placeholder')}
                value={data.email}
                onChange={(element) => setData('email', element.target.value)}
                className={`${errors?.email ? 'border-destructive' : ''}`}
              />
              <FieldErrorBag errors={errors} field="email" />
            </Field>

            <Field>
              <FieldLabel htmlFor="role">{t('users.action.form.role.label')}</FieldLabel>
              <Select value={data.roleUuid} onValueChange={(v) => setData('roleUuid', v)}>
                <SelectTrigger className={`${errors?.roleUuid ? 'border-destructive' : ''}`}>
                  <SelectValue placeholder={t('users.action.form.role.placeholder')} />
                </SelectTrigger>
                <SelectContent>
                  <SelectGroup>
                    {roles.map((role) => {
                      return (
                        <SelectItem key={role.uuid} value={role.uuid}>
                          <span className="flex gap-x-2 items-center">
                            <span className="capitalize text-sm">{role.tag}</span>
                          </span>
                        </SelectItem>
                      )
                    })}
                  </SelectGroup>
                </SelectContent>
              </Select>
              <FieldErrorBag errors={errors} field="roleUuid" />
            </Field>

            <Field>
              <FieldLabel htmlFor="password">{t('users.action.form.password.label')}</FieldLabel>
              <PasswordInput
                id="password"
                placeholder={t('users.action.form.password.placeholder')}
                value={data.password}
                onChange={(e) => setData('password', e.target.value)}
                className={errors?.password ? 'border-destructive' : ''}
              />
              <FieldErrorBag errors={errors} field="password" />
            </Field>

            <Field>
              <FieldLabel htmlFor="passwordConfirmation">
                {t('users.action.form.password_confirmation.label')}
              </FieldLabel>
              <PasswordInput
                id="passwordConfirmation"
                disabled={data.password === ''}
                placeholder={t('users.action.form.password_confirmation.placeholder')}
                value={data.passwordConfirmation}
                onChange={(element) => setData('passwordConfirmation', element.target.value)}
                className={`${errors?.passwordConfirmation ? 'border-destructive' : ''}`}
              />
              <FieldErrorBag errors={errors} field="passwordConfirmation" />
            </Field>

            {progress && (
              <Progress value={progress.percentage} max={100} className="w-full h-2 rounded mt-2" />
            )}
          </form>
        </ScrollArea>
        <DialogFooter className="gap-y-2">
          <DialogClose asChild>
            <Button variant="outline">{t('users.action.actions.cancel')}</Button>
          </DialogClose>
          <Button type="submit" form="user-form">
            {t(isEdit ? 'users.action.actions.save' : 'users.action.actions.add')}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  )
}

import React, { useState } from 'react'

import User from '#users/dtos/user'
import useDialogState from '#common/ui/hooks/use_dialog_state'

type UsersDialogType = 'add' | 'edit' | 'delete' | 'invite' | 'impersonate' | 'ban' | 'unban'

interface UsersContextType {
  open: UsersDialogType | null
  setOpen: (str: UsersDialogType | null) => void
  currentRow: User | null
  setCurrentRow: React.Dispatch<React.SetStateAction<User | null>>
}

const UsersContext = React.createContext<UsersContextType | null>(null)

interface Props {
  children: React.ReactNode
}

export default function UsersProvider({ children }: Props) {
  const [open, setOpen] = useDialogState<UsersDialogType>(null)
  const [currentRow, setCurrentRow] = useState<User | null>(null)

  return (
    <UsersContext.Provider value={{ open, setOpen, currentRow, setCurrentRow }}>
      {children}
    </UsersContext.Provider>
  )
}

export const useUsers = () => {
  const usersContext = React.useContext(UsersContext)

  if (!usersContext) {
    throw new Error('useUsers has to be used within <UsersContext>')
  }

  return usersContext
}

