import type { HttpContext } from '@adonisjs/core/http'
import type { NextFn } from '@adonisjs/core/types/http'
import { DateTime } from 'luxon'
import { primaryDomain } from '#start/domains'

export default class BanMiddleware {
  allowedRoutes = ['/me/ban', '/logout']

  async handle({ auth, response, request }: HttpContext, next: NextFn) {
    if (this.allowedRoutes.some((route) => request.url().includes(route))) return await next()

    if (auth.isAuthenticated) {
      const user = auth.user!
      if (user.isBanned) {
        // @ts-ignore
        await user.load('ban')

        const now = DateTime.now()
        if (user.ban && user.ban.expiresAt && user.ban.expiresAt <= now) {
          user.isBanned = false
          user.banUuid = null
          await user.save()
          return await next()
        }

        return response.redirect().toRoute('ban.show', {}, { domain: primaryDomain })
      } else return await next()
    } else return await next()
  }
}

